CREATE TRIGGER LG_STLINE_DEL_099_02 ON LG_099_02_STLINE
FOR DELETE
AS
DECLARE @c_lService         SMALLINT
DECLARE @c_SubContract      SMALLINT
DECLARE @c_PStatPlanned     SMALLINT
DECLARE @c_PStatRealized    SMALLINT
DECLARE @c_TrWarehouse      SMALLINT
DECLARE @c_TrWorkStation    SMALLINT
DECLARE @c_RepairOn         SMALLINT
DECLARE @c_RepairOff        SMALLINT
DECLARE @repairTotals       SMALLINT
DECLARE @old_logicalRef     INT
DECLARE @old_ItemRef        INT
DECLARE @old_VariantRef     INT
DECLARE @old_TransDate      DATETIME
DECLARE @old_Month          SMALLINT
DECLARE @old_Year           SMALLINT
DECLARE @old_TrCode         SMALLINT
DECLARE @old_CancFlag       SMALLINT
DECLARE @old_LineType       SMALLINT
DECLARE @old_BilledFlag     SMALLINT
DECLARE @old_DecPrDiff      SMALLINT
DECLARE @old_LProdStat      SMALLINT
DECLARE @old_SourceType     SMALLINT
DECLARE @old_SourceIndex    SMALLINT
DECLARE @old_DestType       SMALLINT
DECLARE @old_DestIndex      SMALLINT
DECLARE @old_SourceWSRef    INT
DECLARE @old_DestWSRef      INT
DECLARE @old_Amount         FLOAT
DECLARE @old_Price          FLOAT
DECLARE @old_PrPrice        FLOAT
DECLARE @old_Unit1CFact     FLOAT
DECLARE @old_Unit2CFact     FLOAT
DECLARE @old_VatPer         FLOAT
DECLARE @old_LineNet        FLOAT
DECLARE @old_DistCost       FLOAT
DECLARE @old_DistAddExp     FLOAT
DECLARE @old_DiffPrice      FLOAT
DECLARE @old_DiffRepPrice   FLOAT
DECLARE @old_ReportRate     FLOAT
DECLARE @old_TrRate         FLOAT
DECLARE @old_VatIncFlag     SMALLINT
DECLARE @old_InvoiceRef     INT
DECLARE @old_OrdTransRef    INT
DECLARE @old_DistOrdLineRef INT
DECLARE @old_StFicheRef     INT
DECLARE @old_IOCode         SMALLINT
DECLARE @old_RlsAmount      FLOAT
DECLARE @old_POrdClsPlnAmnt FLOAT
DECLARE @old_Status         SMALLINT
DECLARE @old_doReserve      SMALLINT
DECLARE @old_PrevRef        INT
DECLARE @old_UOMRef         INT
DECLARE @old_OffTrRef       INT
DECLARE @old_OffRef         INT
DECLARE @old_sourceLink     INT
DECLARE @c_LExpense         SMALLINT
DECLARE @c_LDiscount        SMALLINT
DECLARE @dummy              INT
SELECT @c_lService      = 4,
       @c_SubContract   = 11,
       @c_PStatPlanned  = 1,
       @c_PStatRealized = 0,
       @c_RepairOn      = 1,
       @c_RepairOff     = 0,
       @c_TrWarehouse   = 0,
       @c_TrWorkStation = 1,
       @c_LExpense      = 3,
       @c_LDiscount      = 2
SET @repairTotals = @c_RepairOff
SELECT @old_logicalRef = D.LOGICALREF,
       @old_ItemRef = D.STOCKREF,
       @old_VariantRef = D.VARIANTREF,
       @old_TransDate = D.DATE_,
       @old_Month = D.MONTH_,
       @old_Year  = D.YEAR_,
       @old_TrCode = D.TRCODE,
       @old_CancFlag = D.CANCELLED,
       @old_LineType = D.LINETYPE,
       @old_BilledFlag = D.BILLED,
       @old_DecPrDiff = D.DECPRDIFF,
       @old_LProdStat = D.LPRODSTAT,
       @old_SourceType = D.SOURCETYPE,
       @old_SourceIndex = D.SOURCEINDEX,
       @old_DestType = D.DESTTYPE,
       @old_DestIndex = D.DESTINDEX,
       @old_SourceWSRef = D.SOURCEWSREF,
       @old_DestWSRef = D.DESTWSREF,
       @old_Amount = D.AMOUNT,
       @old_Price = D.PRICE,
       @old_Unit1CFact = D.UINFO1,
       @old_Unit2CFact = D.UINFO2,
       @old_VatPer = D.VAT,
       @old_LineNet = D.LINENET,
       @old_DistCost = D.DISTCOST,
       @old_DistAddExp = D.DISTADDEXP,
       @old_DiffPrice = D.DIFFPRICE,
       @old_DiffRepPrice = D.DIFFREPPRICE,
       @old_ReportRate = D.REPORTRATE,
       @old_VatIncFlag = D.VATINC,
       @old_InvoiceRef = D.INVOICEREF,
       @old_OrdTransRef = D.ORDTRANSREF,
       @old_DistOrdLineRef = D.DISTORDLINEREF,
       @old_StFicheRef = D.STFICHEREF,
       @old_IOCode = D.IOCODE,
       @old_RlsAmount = D.PLNAMOUNT,
       @old_POrdClsPlnAmnt = D.PORDCLSPLNAMNT,
       @old_Status = D.STATUS,
       @old_PrevRef   = D.PREVLINEREF,
       @old_doReserve = D.DORESERVE,
       @old_UOMRef    = D.UOMREF,
       @old_OffTrRef  = D.OFFTRANSREF,
       @old_OffRef    = D.OFFERREF,
    @old_sourceLink  = D.SOURCELINK
FROM DELETED D
IF ((@old_LineType = @c_lService) OR (@old_LineType = @c_SubContract))
    EXECUTE LG_UPDATESRVFORTRANS_099_02 @old_ItemRef, @old_TransDate,
                                        @old_TrCode, @old_CancFlag,
                                        @old_SourceIndex, @old_VatIncFlag,
                                        @old_OrdTransRef,
                                        @old_Unit1CFact, @old_Unit2CFact,
                                        @old_VatPer, @old_DistCost,
                                        @old_DistAddExp, @old_Price,
                                        @old_ReportRate, @old_Amount,
                                        -1, @old_Status,
                                        @old_Month, @old_Year, @old_OffTrRef, @old_OffRef, @old_BilledFlag
ELSE
    EXECUTE LG_STKHANDLENUMBERS_099_02 @old_ItemRef, @old_VariantRef, @old_TransDate,
                                       @old_TrCode, -1, @old_CancFlag,
                                       @old_LineType, @old_BilledFlag,
                                       @old_DecPrDiff, @old_LProdStat,
                                       @old_SourceType, @old_DestType,
                                       @old_SourceWSRef, @old_DestWSRef,
                                       @old_SourceIndex, @old_DestIndex,
                                       @old_Amount, @old_Price,
                                       @old_Unit1CFact, @old_Unit2CFact,
                                       @old_VatPer, @old_DistCost,
                                       @old_DistAddExp, @old_DiffPrice,
                                       @old_DiffRepPrice, @old_ReportRate,
                                       @old_VatIncFlag, @old_InvoiceRef,
                                       @old_OrdTransRef, @old_DistOrdLineRef,
                                       @old_StFicheRef, @old_IOCode,
                                       @old_RlsAmount, @old_POrdClsPlnAmnt,
                                       @old_Status, @old_doReserve,
                                       @old_Month, @old_Year, @old_UOMRef, @old_OffTrRef, @old_OffRef
IF @old_ItemRef <> 0
 EXECUTE LG_UPDATEMRPITMCHNG_099 @old_ItemRef, @old_VariantRef, @old_PrevRef
IF (@old_CancFlag = 0) AND (@old_OrdTransRef <> 0) AND (@old_LineType <> @c_lExpense) AND (@old_LineType <> @c_LDiscount)
 BEGIN
   EXECUTE LG_UPDSHIPPEDAMOUNT_099_02 @old_logicalRef, @old_OrdTransRef, @old_sourceLink,
                                    @old_Amount, @old_transDate, @old_Unit1CFact, @old_Unit2CFact, -1
      EXECUTE LG_UPDSHIPPEDAMOUNTORD_099_02 @old_OrdTransRef
 END
